import { React, useState } from 'react'
import TextField from '@mui/material/TextField';
import Button from '@mui/material/Button';
import { FormControl, FormLabel, Stack } from '@mui/material';
import styled from '@emotion/styled'
import { Link, Navigate, useNavigate } from 'react-router-dom'
import useAuth from '../hooks/useAuth'
import supabaseClient from '../supabase'


const LoginForm = () => {

    const { user, setUser } = useAuth()

    const navigate = useNavigate()

    const [error, setError ] = useState()

    const dataUser = e => {
        setUser({
            ...user,
            [e.target.name]: e.target.value
        })
    }


    const handleSubmit = async(e) => {

        e.preventDefault()

        setError('')

        try {

            await supabaseClient.auth.signInWithPassword(user.email, user.password)
            
            navigate('/')

        } catch(error) {

            if ( error.code === "auth/user-not-found")
            {
                setError('El usuario ingresado no existe.');
            } else if ( error.code === "auth/wrong-password")
            {
                setError('La contraseña no es correcta.');
            } else if ( error.code === "auth/internal-error")
            {
                setError('Se debe ingresar la contraseña.');
            } else if ( error.code === "auth/invalid-email")
            {
                setError('Se debe ingresar un mail válido.');
            } else
            {
                setError('Se produjo un error. Volvé a intentar más tarde.');
            }
                
        }
        
    }
    

  return (
        <>
        {   
            <Stack>
                <FormControl>
                    <FormLabel>Enter Name</FormLabel>
                    <TextField></TextField>
                    <Button>Submit</Button>
                </FormControl>
            </Stack>            
}
        </>
  )
}

export default LoginForm
